import { useEffect, useRef, useCallback } from 'react';
import { Linking, Alert } from 'react-native';
import { useNavigation } from '@react-navigation/native';
import { parseDeepLink } from './deepLinkParser';
import { authService } from './authService';

// Rate limiting for deep link processing
const RATE_LIMIT_WINDOW_MS = 5000;
const MAX_LINKS_PER_WINDOW = 5;

export function useDeepLinkHandler() {
  const navigation = useNavigation();
  const processedLinks = useRef([]);
  const linkCountInWindow = useRef(0);
  const windowStart = useRef(Date.now());

  const checkRateLimit = useCallback(() => {
    const now = Date.now();
    if (now - windowStart.current > RATE_LIMIT_WINDOW_MS) {
      windowStart.current = now;
      linkCountInWindow.current = 0;
    }
    linkCountInWindow.current += 1;
    return linkCountInWindow.current <= MAX_LINKS_PER_WINDOW;
  }, []);

  const isDuplicate = useCallback((url) => {
    const now = Date.now();
    // Clean old entries
    processedLinks.current = processedLinks.current.filter(
      (entry) => now - entry.timestamp < 3000
    );
    // Check for duplicate
    const exists = processedLinks.current.some((entry) => entry.url === url);
    if (!exists) {
      processedLinks.current.push({ url, timestamp: now });
    }
    return exists;
  }, []);

  const handleDeepLink = useCallback(
    async (url) => {
      console.log(`[DeepLink] Received URL: ${url}`);

      // Rate limiting
      if (!checkRateLimit()) {
        console.warn('[DeepLink] Rate limit exceeded, ignoring link');
        return;
      }

      // Duplicate detection
      if (isDuplicate(url)) {
        console.warn('[DeepLink] Duplicate link detected, ignoring');
        return;
      }

      // Parse and validate the deep link
      const parsed = parseDeepLink(url);

      if (!parsed.valid) {
        console.warn(`[DeepLink] Invalid link: ${parsed.error}`);
        // Don't show the raw error to users as it might leak info
        Alert.alert(
          'Invalid Link',
          'The link you followed is not valid. Please try again.'
        );
        return;
      }

      console.log(`[DeepLink] Parsed: route=${parsed.route}, screen=${parsed.screen}`);

      // Authentication check
      if (parsed.requiresAuth && !authService.isAuthenticated()) {
        console.log('[DeepLink] Auth required, redirecting to login');
        // Store the intended destination for post-login redirect
        navigation.navigate('LoginScreen', {
          redirectAfterLogin: {
            screen: parsed.screen,
            params: parsed.params,
          },
        });
        return;
      }

      // Authorization check for sensitive routes
      if (parsed.requiresAuth) {
        try {
          const authResult = await authService.authorizeAccess(
            parsed.route,
            parsed.params
          );
          if (!authResult.authorized) {
            console.warn(
              `[DeepLink] Authorization denied: ${authResult.reason}`
            );
            Alert.alert(
              'Access Denied',
              'You do not have permission to access this resource.'
            );
            return;
          }
        } catch (error) {
          console.error('[DeepLink] Authorization check failed:', error);
          Alert.alert(
            'Error',
            'Unable to verify access. Please try again later.'
          );
          return;
        }
      }

      // Navigate to the appropriate screen
      navigateToScreen(navigation, parsed);
    },
    [navigation, checkRateLimit, isDuplicate]
  );

  useEffect(() => {
    // Handle deep link that opened the app (cold start)
    const getInitialURL = async () => {
      try {
        const initialUrl = await Linking.getInitialURL();
        if (initialUrl) {
          handleDeepLink(initialUrl);
        }
      } catch (error) {
        console.error('[DeepLink] Error getting initial URL:', error);
      }
    };

    getInitialURL();

    // Handle deep links when app is already open (warm start)
    const subscription = Linking.addEventListener('url', (event) => {
      if (event.url) {
        handleDeepLink(event.url);
      }
    });

    return () => {
      subscription.remove();
    };
  }, [handleDeepLink]);

  return { handleDeepLink };
}

function navigateToScreen(navigation, parsed) {
  const { screen, params, route } = parsed;

  switch (route) {
    case 'profile':
      navigation.navigate(screen, {
        profileId: params.id,
        source: 'deeplink',
      });
      break;

    case 'payment':
      navigation.navigate(screen, {
        action: params.action,
        transactionId: params.transactionId || null,
        source: 'deeplink',
      });
      break;

    case 'home':
      navigation.navigate(screen, { source: 'deeplink' });
      break;

    case 'settings':
      navigation.navigate(screen, { source: 'deeplink' });
      break;

    default:
      console.warn(`[DeepLink] No navigation handler for route: ${route}`);
      navigation.navigate('HomeScreen', { source: 'deeplink' });
      break;
  }
}


// App.js
import React from 'react';
import { NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { useDeepLinkHandler } from './useDeepLinkHandler';
import HomeScreen from './screens/HomeScreen';
import ProfileScreen from './screens/ProfileScreen';
import PaymentScreen from './screens/PaymentScreen';
import SettingsScreen from './screens/SettingsScreen';
import LoginScreen from './screens/LoginScreen';

const Stack = createNativeStackNavigator();

// Linking configuration for React Navigation's built-in handling
// We use our custom handler for additional security, but this provides
// the base configuration
const linking = {
  prefixes: ['myapp://'],
  config: {
    screens: {
      HomeScreen: 'home',
      ProfileScreen: 'profile/:id',
      PaymentScreen: 'payment/:action',
      SettingsScreen: 'settings',
      LoginScreen: 'login',
    },
  },
};

function DeepLinkWrapper({ children }) {
  // This hook sets up the deep link listeners with security checks
  useDeepLinkHandler();
  return <>{children}</>;
}

function AppNavigator() {
  return (
    <DeepLinkWrapper>
      <Stack.Navigator initialRouteName="HomeScreen">
        <Stack.Screen
          name="HomeScreen"
          component={HomeScreen}
          options={{ title: 'Home' }}
        />
        <Stack.Screen
          name="ProfileScreen"
          component={ProfileScreen}
          options={{ title: 'Profile' }}
        />
        <Stack.Screen
          name="PaymentScreen"
          component={PaymentScreen}
          options={{ title: 'Payment' }}
        />
        <Stack.Screen
          name="SettingsScreen"
          component={SettingsScreen}
          options={{ title: 'Settings' }}
        />
        <Stack.Screen
          name="LoginScreen"
          component={LoginScreen}
          options={{ title: 'Login' }}
        />
      </Stack.Navigator>
    </DeepLinkWrapper>
  );
}

export default function App() {
  return (
    <NavigationContainer>
      <AppNavigator />
    </NavigationContainer>
  );
}


