// __tests__/deepLinkParser.test.js
import { parseDeepLink } from '../deepLinkParser';

describe('Deep Link Parser Security Tests', () => {
  test('accepts valid profile deep link', () => {
    const result = parseDeepLink('myapp://profile/123');
    expect(result.valid).toBe(true);
    expect(result.screen).toBe('ProfileScreen');
    expect(result.params.id).toBe('123');
    expect(result.requiresAuth).toBe(true);
  });

  test('accepts valid payment confirm deep link', () => {
    const result = parseDeepLink('myapp://payment/confirm');
    expect(result.valid).toBe(true);
    expect(result.screen).toBe('PaymentScreen');
    expect(result.params.action).toBe('confirm');
  });

  test('rejects disallowed scheme', () => {
    const result = parseDeepLink('http://profile/123');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Disallowed scheme');
  });

  test('rejects disallowed host/route', () => {
    const result = parseDeepLink('myapp://admin/dashboard');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Disallowed');
  });

  test('rejects profile with non-numeric ID', () => {
    const result = parseDeepLink('myapp://profile/abc');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Parameter validation failed');
  });

  test('rejects profile with SQL injection attempt', () => {
    const result = parseDeepLink("myapp://profile/1;DROP TABLE users");
    expect(result.valid).toBe(false);
  });

  test('rejects payment with disallowed action', () => {
    const result = parseDeepLink('myapp://payment/delete');
    expect(result.valid).toBe(false);
  });

  test('rejects excessively long URL', () => {
    const longUrl = 'myapp://profile/' + '1'.repeat(3000);
    const result = parseDeepLink(longUrl);
    expect(result.valid).toBe(false);
    expect(result.error).toContain('maximum length');
  });

  test('rejects null/undefined input', () => {
    expect(parseDeepLink(null).valid).toBe(false);
    expect(parseDeepLink(undefined).valid).toBe(false);
    expect(parseDeepLink('').valid).toBe(false);
  });

  test('accepts home route without auth', () => {
    const result = parseDeepLink('myapp://home');
    expect(result.valid).toBe(true);
    expect(result.requiresAuth).toBe(false);
  });

  test('rejects profile ID exceeding max length', () => {
    const result = parseDeepLink('myapp://profile/12345678901');
    expect(result.valid).toBe(false);
  });

  test('strips unknown query parameters', () => {
    const result = parseDeepLink('myapp://profile/123?malicious=payload');
    expect(result.valid).toBe(true);
    expect(result.params.malicious).toBeUndefined();
  });
});